import{_ as r,o as n,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"USt.-Verwaltung","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/vat.md","filePath":"de/features/vat.md"}'),a={name:"de/features/vat.md"};function l(s,e,h,o,d,u){return n(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="ust-verwaltung" tabindex="-1">USt.-Verwaltung <a class="header-anchor" href="#ust-verwaltung" aria-label="Permalink to &quot;USt.-Verwaltung&quot;">​</a></h1><p>Verfolgen, berechnen und verwalten Sie Ihre Umsatzsteuer-Verpflichtungen mit Periodensperren und Fristenverfolgung.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Die USt.-Seite gibt Ihnen einen klaren Überblick über Ihre Steuersituation:</p><ul><li><strong>Erhobene USt.</strong> — Steuer, die auf Ihren Rechnungen berechnet wurde</li><li><strong>Abziehbare USt.</strong> — Steuer, die auf Ihre Geschäftsausgaben gezahlt wurde</li><li><strong>Netto-USt.</strong> — Der Betrag, den Sie schulden (oder zurückfordern können)</li></ul><h2 id="ust-perioden" tabindex="-1">USt.-Perioden <a class="header-anchor" href="#ust-perioden" aria-label="Permalink to &quot;USt.-Perioden&quot;">​</a></h2><p>Die USt. ist nach Perioden organisiert (monatlich oder vierteljährlich, je nach Ihrer Zuständigkeit):</p><ul><li>USt.-Berechnungen pro Periode anzeigen</li><li>Detaillierte Aufschlüsselungen nach USt.-Satz sehen</li><li>Verfolgen, welche Perioden eingereicht wurden</li></ul><h2 id="periodensperre" tabindex="-1">Periodensperre <a class="header-anchor" href="#periodensperre" aria-label="Permalink to &quot;Periodensperre&quot;">​</a></h2><p>Nach Einreichung Ihrer USt.-Erklärung sperren Sie die Periode, um versehentliche Änderungen zu verhindern:</p><ol><li>Gehen Sie zur USt.-Seite</li><li>Wählen Sie die Periode, die Sie eingereicht haben</li><li>Klicken Sie auf <strong>Periode sperren</strong></li></ol><h3 id="was-die-sperre-bewirkt" tabindex="-1">Was die Sperre bewirkt <a class="header-anchor" href="#was-die-sperre-bewirkt" aria-label="Permalink to &quot;Was die Sperre bewirkt&quot;">​</a></h3><ul><li>Verhindert das Bearbeiten oder Löschen von Rechnungen und Ausgaben in der gesperrten Periode</li><li>Zeigt ein Warnbanner auf Dokumenten innerhalb gesperrter Perioden</li><li>Stellt sicher, dass Ihre eingereichten Zahlen mit Ihren Aufzeichnungen übereinstimmen</li></ul><h3 id="entsperren" tabindex="-1">Entsperren <a class="header-anchor" href="#entsperren" aria-label="Permalink to &quot;Entsperren&quot;">​</a></h3><p>Wenn Sie nach der Sperre Korrekturen vornehmen müssen:</p><ol><li>Gehen Sie zur USt.-Seite</li><li>Finden Sie die gesperrte Periode</li><li>Klicken Sie auf <strong>Entsperren</strong></li><li>Nehmen Sie Ihre Korrekturen vor</li><li>Sperren Sie erneut, wenn Sie fertig sind</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Entsperren Sie Perioden nur, wenn Sie eine Korrektur einreichen müssen. Häufiges Entsperren untergräbt den Zweck der Compliance-Sicherung.</p></div><h2 id="fristenverfolgung" tabindex="-1">Fristenverfolgung <a class="header-anchor" href="#fristenverfolgung" aria-label="Permalink to &quot;Fristenverfolgung&quot;">​</a></h2><p>MyCompanyDesk verfolgt USt.-Einreichungsfristen basierend auf Ihrem Land:</p><ul><li>Visuelle Indikatoren für bevorstehende Fristen</li><li>Warnungen, wenn eine Frist naht</li><li>Klarer Status, welche Perioden Aufmerksamkeit erfordern</li></ul><h2 id="landerindikator" tabindex="-1">Länderindikator <a class="header-anchor" href="#landerindikator" aria-label="Permalink to &quot;Länderindikator&quot;">​</a></h2><p>Ihre USt.-Einstellungen respektieren das Registrierungsland Ihres Unternehmens. Dies beeinflusst:</p><ul><li>Standard- und ermäßigte USt.-Sätze</li><li>Struktur der Meldeperioden (monatlich/vierteljährlich)</li><li>Fristenberechnungen</li><li>Anwendbarkeit der Reverse-Charge-Regelung</li></ul><h2 id="reverse-charge" tabindex="-1">Reverse-Charge <a class="header-anchor" href="#reverse-charge" aria-label="Permalink to &quot;Reverse-Charge&quot;">​</a></h2><p>Für innergemeinschaftliche B2B-Transaktionen aktivieren Sie die Reverse-Charge-Regelung:</p><ol><li>Stellen Sie sicher, dass der Kunde eine gültige EU-USt.-Nummer hat</li><li>Aktivieren Sie <strong>Reverse-Charge</strong> unter Unternehmen &gt; Funktionen</li><li>Wählen Sie beim Erstellen einer Rechnung für einen EU-B2B-Kunden die Reverse-Charge-Option</li><li>Die Rechnung zeigt 0 % USt. mit dem Reverse-Charge-Vermerk</li></ol><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Sperren Sie Perioden sofort nach der Einreichung, um versehentliche Änderungen zu verhindern</li><li>Überprüfen Sie den USt.-Bericht in den <a href="/de/features/reports">Berichten</a> für einen breiteren Überblick</li><li>Stellen Sie sicher, dass sowohl Ihre USt.-Nummer als auch die USt.-Nummern Ihrer Kunden korrekt eingegeben sind</li><li>Verwenden Sie das Buchhalter/Steuerberater-Dashboard-Profil für eine USt.-fokussierte Ansicht</li></ul>',28)])])}const p=r(a,[["render",l]]);export{g as __pageData,p as default};
